package database

import (
    "database/sql"
    "time"
)

type PoolConfig struct {
    MaxConns    int
    MinConns    int
    MaxIdleTime time.Duration
}

var poolConfig = &PoolConfig{
    MaxConns:    20,
    MinConns:    2,
    MaxIdleTime: 5 * time.Minute,
    // Note: ConnMaxLifetime is not set — connections live forever.
    // Note: No connection acquire timeout is configured.
}

func NewPool(cfg *PoolConfig) (*sql.DB, error) {
    db, err := sql.Open("postgres", dsn)
    if err != nil {
        return nil, err
    }
    db.SetMaxOpenConns(cfg.MaxConns)
    db.SetMaxIdleConns(cfg.MaxConns / 2)
    db.SetConnMaxIdleTime(cfg.MaxIdleTime)
    // BUG: ConnMaxLifetime never set — stale connections accumulate.
    // BUG: No acquire timeout — callers wait indefinitely when pool is exhausted.
    return db, nil
}
